head.script:
//-------------------------------------------------------------------------
// 추후 수정사항
// 호출 팝업 미개발로 추후 연결
//-------------------------------------------------------------------------


//-------------------------------------------------------------------------
// 전역 변수
//-------------------------------------------------------------------------
scwin.loUpperLobranCd = $c.data.getMemInfo("loUpperLobranCd"); // 회원 점소 데이터
scwin.vCurDate = WebSquare.date.getCurrentServerDate();  // 서버를 기준으로 현재 날짜 반환

// 호출화면에서부터 전달받는 파라미터 
scwin.param = "";
scwin.lobranCd = "";
scwin.wrkStDt = "";
scwin.wrkEndDt = "";
scwin.cntrNo = "";
scwin.odrNo = "";

scwin.afterSaveRetrieveYN = "YES";
scwin.g_chkScroll = false;
scwin.g_chkScroll2 = false;

//-------------------------------------------------------------------------
// 화면 로딩시
//-------------------------------------------------------------------------
scwin.onpageload = function() {

    scwin.param = $c.data.getParameter();
    scwin.wrkStDt = scwin.param.wrkStDt == null ? "" : scwin.param.wrkStDt;
    scwin.wrkEndDt = scwin.param.wrkEndDt == null ? "" : scwin.param.wrkEndDt;
    scwin.lobranCd = scwin.param.lobranCd == null ? "" : scwin.param.lobranCd;
    scwin.cntrNo = scwin.param.cntrNo == null ? "" : scwin.param.cntrNo;
    scwin.odrNo = scwin.param.odrNo == null ? "" : scwin.param.odrNo;




    const param= [
        {
            method: "getLuxeComboData",
            param1: "WorkImplementEBC",
            param2: "retriveLobran2CodeList",
            compID: "acb_lobranCd"
        }
    ];
    $c.data.setGauceUtil(param);


    const codeOptions = [
        { grpCd: "OP194", compID: "acb_impExpDomesticClsCd" }
        , // 셀렉트
        { grpCd: "OP196", compID: "acb_cntrWrkKndCd, gr_resultsforexcel:cntrWrkShapeCd" }, // 셀렉트
    ];
    $c.data.setCommonCode(codeOptions);

    cbx_alloccarYn.setValue("1");


};

setTimeout (scwin.ondataload = function() {
    // console.log("??"+scwin.lobranCd+"?");
    // console.log("이거잖아 "+scwin.loUpperLobranCd);

    if(scwin.lobranCd == "") {
        // console.log("분기1");
        acb_lobranCd.setValue(scwin.loUpperLobranCd);
    } else {
        // console.log("분기2");
        acb_lobranCd.setValue(scwin.lobranCd);
    }

}, 200);


//-------------------------------------------------------------------------
// 기본 날짜값 세팅
//-------------------------------------------------------------------------
scwin.onUdcCompleted = function() {
    let curData = scwin.vCurDate;
    let wrkDt = scwin.wrkStDt;

    if(scwin.wrkStDt == "") {
        udc_dptIntendDd.setInitDate(curData, curData);
    } else {
        udc_dptIntendDd.setInitDate(wrkDt, wrkDt);
    }

   if(scwin.lobranCd == "") {
        acb_lobranCd.setValue(scwin.loUpperLobranCd);
    } else {
        acb_lobranCd.setValue(scwin.lobranCd);
    }


    if(scwin.cntrNo != "") {
        acb_noClsCd.setValue("C");
        ed_cntrOdrNo.setValue(scwin.cntrNo);
        scwin.btn_retrieve_onClick();
    } else if(scwin.odrNo != "") {
        acb_noClsCd.setValue("O");
        ed_cntrOdrNo.setValue(scwin.odrNo);
        scwin.btn_retrieve_onClick();
    } else {
        acb_noClsCd.setValue("O");
    }

    gr_resultsforexcel.hideGroupbyZone();

};


//-------------------------------------------------------------------------
// 대문자 변환
//-------------------------------------------------------------------------
scwin.onkeyup = function (e) {
    this.setValue(e.target.value.toUpperCase());
};


//-------------------------------------------------------------------------
// 엑셀 다운로드
//-------------------------------------------------------------------------
scwin.f_runExcel = async function() {
    udc_grid_excel.setGridId(gr_resultsforexcel);

    let options = {
        fileName : "컨테이너운송지시.xlsx",
        sheetName : "컨테이너운송지시",
        removeColumns  : "1,3,4,8,9,11"
    }

    let grdObj = gr_resultsforexcel;

    let infoArr = {};

    // $c.data.download
    if(ds_results.getTotalRow() == 0) {
        $c.win.alert(MSG_CM_WRN_002);
    } else {
        if(await $c.win.confirm("EXCEL로 다운로드 받으시겠습니까?")) {
            $c.data.downloadGridViewExcel(grdObj, options, infoArr)
        }
    }

}

//-------------------------------------------------------------------------
// 조회
//-------------------------------------------------------------------------
scwin.btn_retrieve_onClick = async function (e) {
    scwin.g_chkScroll = false;
    scwin.g_chkScroll2 = false;

    let rtnVal = cbx_alloccarYn.getValue();

    if(acb_noClsCd.getValue() == "C"){
            let cntrOdrNo = ed_cntrOdrNo.getValue();
            if(await $c.gus.cfGetByteLength(cntrOdrNo) != 11){
                $c.win.alert("컨테이너 번호 11자리를 입력해주세요.");
                return;
            }
        }

        if(!await $c.gus.cfIsAfterDate(ica_dptIntendDd.getValue(), ica_dptIntendDd2.getValue())){
            $c.win.alert(MSG_CM_ERR_039);
            ica_dptIntendDd.focus();
            return;
        }

    dma_search.set("lobranCd", acb_lobranCd.getValue());
    dma_search.set("dptIntendDd", ica_dptIntendDd.getValue());
    dma_search.set("dptIntendDd2", ica_dptIntendDd2.getValue());


    $c.sbm.execute(sbm_retrieve);        

};


//-------------------------------------------------------------------------
// 저장
//-------------------------------------------------------------------------
scwin.btn_SaveGroup_onClick = async function (e) {

    if(ds_results.getModifiedIndex().length == 0){
        $c.win.alert("변경된 사항이 없습니다.");
        return;
    }
    await $c.sbm.execute(sbm_saveGroup);
}

//-------------------------------------------------------------------------
// 저장 완료시
//-------------------------------------------------------------------------
scwin.sbm_saveGroup_submitDone = async function (e) {
    await $c.win.alert(MSG_CM_INF_001);
    scwin.btn_retrieve_onClick();

};


//-------------------------------------------------------------------------
// 취소
//-------------------------------------------------------------------------
scwin.btn_deleteGroup_onClick = async function (e) {
    if(await $c.win.confirm(MSG_CM_CRM_011)) {
        ds_results.setCellData(0, "status", "allDel");
        await $c.sbm.execute(sbm_saveGroup);
    }
};


//-------------------------------------------------------------------------
// 데이터 로드시
//-------------------------------------------------------------------------
scwin.ds_results_ondataload = function () {
    let rowCnt = ds_results.getRowCount();
    spa_totalRows1.setValue(rowCnt);



    scwin.g_chkScroll = true;
	scwin.g_chkScroll2 = false;

	if( rowCnt == 0 ){
		// ds_results2.ClearData();
		// ds_dcScList.ClearData();
		$c.win.alert("조회된 데이터가 없습니다.");
	}

    if(cbx_alloccarYn.getValue() == "1") {
        scwin.f_filter();
    }

    // 조회 완료시 돌면서 value 넣어주기
    for(i = 0; i < ds_results.getRowCount(); i++) {

        // 청구 화주 cell 색상 변경
        if(ds_results.getCellData(i, "odrDtYn") == "Y") {
            gr_results.setCellColor(i, "realMchtClntNm", "#FBCED4");
        }

        if(ds_results.getCellData(i, "prtClsCd") == "1") {
            gr_results.setCellColor(i, "odrNo", "red");
        } else {
            gr_results.setCellColor(i, "odrNo", "blue");
        }

        if(ds_results.getCellData(i, "prtClsCdprtClsCd") == "1") {
            gr_resultsforexcel.setCellColor(i, "odrNo", "red");
        } else {
            gr_resultsforexcel.setCellColor(i, "odrNo", "blue");
        }



        gr_results.setCellColor(i, "vehclInfoRed", "red");
        gr_results.setCellColor(i, "vehclInfoBlack", "black");

        ds_results.modifyRowStatus(i, "R");
    }

    let rowFilter = ds_results.getRowCount();

    if(rowFilter == 0) {
        $c.win.alert("조회된 데이터가 없습니다.");
    }


    ds_results.sort("grpCd", 1);

};

//-------------------------------------------------------------------------
// 배차숨기기 체크박스 여부에 따른 필터
//-------------------------------------------------------------------------
scwin.f_filter = function (info) {
    ds_results.clearFilter();

    if(cbx_alloccarYn.getValue() == "0") {
        spa_totalRows1.setValue(ds_results.getRowCount());
        ds_results.sort("grpCd", 1);
        return;
    } else {

        let fn_tmpDeptFilter = function(cellData, tmpParam, rowIdx){
        if(ds_results.getCellData(rowIdx, "totCnt") === ds_results.getCellData(rowIdx, "totRsltsCnt")){
            // ds_results.sort("grpCd", 1);
                return false;
            }else {
                // ds_results.sort("grpCd", 1);
                return true;   // return이 true인 경우 적용하고 false인 경우 넘김
            }
        }   

        ds_results.setColumnFilter( 
            {type:"func", colIndex:"totCnt", key:fn_tmpDeptFilter, condition:"and"}
        );

        // ds_results.sort("grpCd", 1);
    }

    ds_results.sort("grpCd", 1);
    spa_totalRows1.setValue(ds_results.getRowCount());


};


//-------------------------------------------------------------------------
// 요청담당자 UDC Click
//-------------------------------------------------------------------------
scwin.udc_req_onclickEvent = function (e) {
    scwin.f_openCommonPopUp(1,ed_reqId.getValue(), ed_reqNm.getValue(),"F","F")

};

//-------------------------------------------------------------------------
// 요청담당자 UDC Code Blur
//-------------------------------------------------------------------------
scwin.udc_req_onblurCodeEvent = function (e) {
    scwin.f_chkOpenCommonPopUp(ed_reqId, ed_reqNm, 1) // 6
};


//-------------------------------------------------------------------------
// 팝업 처리시 검색된 데이터인 경우 팝업 처리 안함.
//-------------------------------------------------------------------------
scwin.f_chkOpenCommonPopUp = function(inObj, pairObj, disGubun, isCode) {

    // 값이 입력이 안된 경우, 해당 Text Box가 readonly 인 경우, 이전값과 동일한 경우 팝업을 실행하지 않음.
    if (!$c.gus.cfCanOpenPopup(inObj, pairObj)) {
        return;
    }


    // 짝이 되는 오브젝트의 값 제거
    $c.gus.cfClearPairObj(pairObj);

    // 검색어 세팅
    let pVal = $c.gus.cfGetValue(inObj);

    // inObj가 코드 필드일 경우 팝업
    if (isCode == null || isCode == true)
        scwin.f_openCommonPopUp(disGubun, pVal, '', 'T', 'T');
    // inObj가 코드명 필드일 경우 팝업
    else
        scwin.f_openCommonPopUp(disGubun, '', pVal, 'T', 'T');    
}


//-------------------------------------------------------------------------
// 공통 Popup 처리 : Gubun Code 에 따른 공통 Popup 을 호출한다.
//-------------------------------------------------------------------------
scwin.f_openCommonPopUp = function(disGubun, pCode, pName, pClose, pAllSearch) {
	// 선언부
    let rtnList;  // 공통POP-UP -> 요청화면 
    switch (disGubun) {

        case 1:
            //요청담당자
            udc_req.cfCommonPopUp(scwin.udc_req_CallBack	// XML상의 SELECT ID	
                                    ,pCode					// 화면에서의 ??? Code Element의	Value
                                    ,pName					// 화면에서의 ??? Name Element의	Value
                                    ,pClose					// 결과가 1건 일때  원도우를	AutoClose 여부	(T:Close,F:Opened)
                                    ,null					// 검색 결과	컬럼의 보여주는	개수 (SELECT절의 순서) MAX:10 - default (2)
                                    ,null					// Title순서	
                                    ,null					// 보여주는 각 컬럼들의 폭	
                                    ,null					// 컬럼중에서 숨기는	컬럼 지정	
                                    ,null					// SQL절의 WHERE절에	원하는 조건을 선택함 MAX:8개까지 가능
                                    ,null					// POP-UP뛰을때 원도우의	사용자 정의	폭
                                    ,null					// POP-UP뛰을때 우도우의	사용자 정의	높이	
                                    ,null					// 윈도우 위치 Y좌표	
                                    ,null					// 윈도우 위치 X좌표
                                    ,null					// 중복체크여부	("F")
                                    ,pAllSearch				// 전체검색허용여부	("F")
                                    ,null					// POP-UP Window Title 검색어1,2	 ("Win타이틀,첫번검색Nm,두번?검색Nm")
                                    );
            break;	
    }
}

//-------------------------------------------------------------------------
// 요청 담당자 팝업 콜백
//-------------------------------------------------------------------------
scwin.udc_req_CallBack = function(rtnList) {
    if(rtnList != null) {
        $c.gus.cfSetReturnValue(rtnList, ed_reqId, ed_reqNm);
    } else {
        ed_reqId.setValue("");
        ed_reqNm.setValue("");
    }
}


//-------------------------------------------------------------------------
// 그리드 오더 구분 Decode
//-------------------------------------------------------------------------
scwin.reqClsCd_display = function(data){
    return $c.gus.decode(data, 
        "A", "지정",
        "B", "미지정",
        "C", "지정(범위)",
        "D", "첫배차"
    );
};

//-------------------------------------------------------------------------
// 그리드 작업단계 Decode
//-------------------------------------------------------------------------
scwin.wrkStpCd_display = function(data){
    return $c.gus.decode(data, 
        "0002", "운송",
        "0003", "회수",
        "0047", "육송"
    );
};

//-------------------------------------------------------------------------
// 그리드 O/B Decode
//-------------------------------------------------------------------------
scwin.cntrWrkShapeCd_display = function(data, formattedData, rowIndex, colIndex){

    return $c.gus.decode(data, 
        "IO", "I/O", data
    );

};


//-------------------------------------------------------------------------
// 조회 성공시
//-------------------------------------------------------------------------
scwin.retrieve_submitDone = function (e) {
    gr_results.setFocusedCell(0, 0);

    if(gr_results.getFocusedColumnIndex() >= 0) {
        txa_vehcl_red.setValue(ds_results.getCellData(0, "vehclInfoRed"))
        txa_vehcl_black.setValue(ds_results.getCellData(0, "vehclInfoBlack"))
        txa_rmk.setValue(ds_results.getCellData(0, "rmk"))
    } else {
        txa_vehcl_red.setValue("")
        txa_vehcl_black.setValue("")
        txa_rmk.setValue("")
    }
};

//-------------------------------------------------------------------------
// 그리드 Cell 더블 클릭
//-------------------------------------------------------------------------
scwin.gr_results_oncelldblclick = async function (rowIndex, columnIndex, columnId) {
    let options = {};
    let arrParam = [];
    let rtnList = "";



	switch (columnId) {
		case "odrNo":
            arrParam[0] = ds_results.getCellData(rowIndex,"odrNo");
            arrParam[1] = ds_results.getCellData(rowIndex,"cntrSeq");
            arrParam[2] = ds_results.getCellData(rowIndex,"wrkLobranCd");
            arrParam[3] = ds_results.getCellData(rowIndex,"reqClsCd");
            arrParam[4] = ds_results.getCellData(rowIndex,"transCls");
            arrParam[5] = ds_results.getCellData(rowIndex,"cntrSizCd");
            arrParam[6] = ds_results.getCellData(rowIndex,"cntrTypCd");
            arrParam[7] = ds_results.getCellData(rowIndex,"reqDt");
            arrParam[8] = ds_results.getCellData(rowIndex,"reqHh");
            arrParam[9] = ds_results.getCellData(rowIndex,"reqDoorCd");


            // 팝업 옵션 설정
            options = {
                id: "taxPop", 
                type: "browserPopup",
                popupName: "배차지시",
                width:  1100,                   
                height: 830
            };


            await $c.win.openPopup("/ui/tn/os/odrrslts/odrrslts/tn_501_01_02p.xml", options, arrParam);   
			scwin.btn_retrieve_onClick();

        break;

		case "cntrWrkShapeCd":

            let cntrOdrNo = "";

			if(acb_noClsCd.getValue() == "O") {
                cntrOdrNo = ds_results.getCellData(ds_results.getRowPosition(),"odrNo");
			}
			else {
				cntrOdrNo = ed_cntrOdrNo.getValue();
			}

            arrParam[0] = ds_results.getCellData(ds_results.getRowPosition(),"wrkLobranCd");
            arrParam[1] = ica_dptIntendDd.getValue(); 
            arrParam[2] = ica_dptIntendDd2.getValue();
            arrParam[3] = acb_noClsCd.getValue();
            arrParam[4] = "N";
            arrParam[5] = "";
            arrParam[6] = "";
            arrParam[7] = cntrOdrNo;
            arrParam[8] = "";
            arrParam[9] = "";
            arrParam[10] = "C";

            // 팝업 옵션 설정
            options = {
                id: "taxPop", 
                type: "browserPopup",
                popupName: "배차지시",
                width:  1100,                   
                height: 650
            };


            await $c.win.openPopup("/ui/tn/os/odrrslts/odrrslts/tn_501_01_03p.xml", options, arrParam);   

            scwin.btn_retrieve_onClick();		
        break;
	}


};


//-------------------------------------------------------------------------
// 그리드 Cell 클릭
//-------------------------------------------------------------------------
scwin.gr_results_oncellclick = function (rowIndex, columnIndex, columnId) {
	txa_vehcl_red.setValue(ds_results.getCellData(rowIndex, "vehclInfoRed"));
	txa_vehcl_black.setValue(ds_results.getCellData(rowIndex, "vehclInfoBlack"));
	txa_rmk.setValue(ds_results.getCellData(rowIndex, "rmk"));

	switch (columnId) {
		case "reqQty":
			ds_retrieveCntrInfoQry.removeAll();
		    ds_retrieveCntrInfoQry.insertRow();
		    ds_retrieveCntrInfoQry.setCellData(0, "odrNo", ds_results.getCellData(ds_results.getRowPosition(),"odrNo"));
		    ds_retrieveCntrInfoQry.setCellData(0, "reqDt", ds_results.getCellData(ds_results.getRowPosition(),"reqDt"));
		    ds_retrieveCntrInfoQry.setCellData(0, "reqClsCd", ds_results.getCellData(ds_results.getRowPosition(),"reqClsCd"));

            $c.sbm.execute(sbm_retrieveCntrInfo);

		    let sttr = "";

		    if ( ds_cntrInfo.getTotalRow() > 0 && "D" != ds_retrieveCntrInfoQry.getCellData(0, "reqClsCd")) {
				for(i = 0; i < ds_cntrInfo.getTotalRow(); i++){
					if(i == 1) {
						sttr += ds_cntrInfo.getCellData(i,"cntrNo");
					} 
					else {
						sttr += ", " + ds_cntrInfo.getCellData(i,"cntrNo");
					}
				}
				alert(sttr);
		    } 

			break;			
	}

};


//-------------------------------------------------------------------------
// 조회 필드 Clear
//-------------------------------------------------------------------------
scwin.btn_Trash_onclick = function (e) {

    $c.gus.cfInitObjects(tb_condition, [acb_lobranCd, ica_dptIntendDd, ica_dptIntendDd2]);

};

//-------------------------------------------------------------------------
// Grid Format 설정
//-------------------------------------------------------------------------
scwin.gr_2dc_format = function(data, formattedData, rowIndex, colIndex) {

    return ds_results.getCellData(rowIndex, "dc20RsltsCnt") + "/" +  ds_results.getCellData(rowIndex, "dc20Cnt");
}

scwin.gr_dc_format = function(data, formattedData, rowIndex, colIndex) {
    return ds_results.getCellData(rowIndex, "dc40RsltsCnt") + "/" +  ds_results.getCellData(rowIndex, "dc40Cnt");
} 

scwin.gr_hc_format = function(data, formattedData, rowIndex, colIndex) {

    return ds_results.getCellData(rowIndex, "hc40RsltsCnt") + "/" +  ds_results.getCellData(rowIndex, "hc40Cnt");
} 

scwin.gr_rd_format = function(data, formattedData, rowIndex, colIndex) {

    return ds_results.getCellData(rowIndex, "rd40RsltsCnt") + "/" +  ds_results.getCellData(rowIndex, "rd40Cnt");
} 

scwin.gr_etc_format = function(data, formattedData, rowIndex, colIndex) {
    return ds_results.getCellData(rowIndex, "etcRsltsCnt") + "/" +  ds_results.getCellData(rowIndex, "etcCnt");
} 

scwin.gr_closeDt_format = function(data, formattedData, rowIndex, colIndex) {
    return ds_results.getCellData(rowIndex, "openCloseDt") + "/" +  ds_results.getCellData(rowIndex, "openCloseHh");
}
